INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06150', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '生態圖是協助社會工作人員進行評量（assessment）的工具之一。下列有關生態圖的敘述，何者錯誤？', '["透過生態圖的繪製，可以協助社會工作人員詮釋案主生活的世界", "繪製生態圖，可由案主自己畫，或是社會工作人員與案主一起畫", "生態圖可以幫助社會工作人員視覺化人與環境間的交互關係", "每個服務對象因擁有資源數及互動情況不同，生態圖皆不同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06151', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當案主對自己缺乏自信，且沒有意識到自己被剝奪權力時，社會工作人員可以採用何種技術來幫助他？', '["問題解決", "任務中心", "充權", "同理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06152', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「系統的維護與增強者」是社會工作人員在直接服務範疇中的角色之一，下列有關該角色的敘述，何者 錯誤？', '["包含團隊成員、督導者、組織分析者等角色類型", "係指社會工作人員有責任評估組織機構、機構政策，與阻礙有效服務輸送的機構內部功能的角色", "係指當案主缺乏相關的知識或能力使用其他相關資源時，社會工作人員需幫其連結與開發資源的角色", "在執行這類的角色時，若社會工作人員缺乏相關的專業知識，可以諮詢機構督導或是其他專業人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06153', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作人員在與多元文化案主建立信任關係時，常會藉由「翻譯者」以降低語言或文化對於關係建立 的負向干擾，下列有關「使用翻譯者」的敘述，何者錯誤？', '["社會工作人員應向案主介紹翻譯者，並說明彼此保密的義務", "社會工作人員應優先選擇具有會談技巧且有能力解釋文化差異的翻譯者", "社會工作人員在與聽覺障礙案主會談時，不論是眼神與心思，應聚焦在手語翻譯者的口譯表達", "專業的翻譯者不僅需做到案主語言的解釋，也需瞭解口語以外的行為意義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06154', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當案主說：「我覺得朋友都是不可靠的，我常常被他們出賣」，社會工作人員回應：「我猜你覺得你的 朋友總是讓你很失望，你覺得自己不能太相信他們，要不要舉一個最近讓你有這樣感覺的例子？」請問 社會工作人員是運用了那一種會談技巧？', '["自我揭露", "具體化", "立即性", "面質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06155', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關兒童與老人評估（assessment）的敘述，何者錯誤？', '["兒童與老人是被虐待的高危險群，社會工作人員在進行評估時，應對遭受虐待的指標，抱持高敏感度", "針對老人功能的狀態，應牽涉到不同專業，可透過專業團隊來執行評估", "社會工作人員要積極傾聽兒童與老人如何陳述自己的狀態，這是最可信且最直接的評估資訊", "發展性評估對於瞭解兒童過去的發展歷史與現況，是非常重要的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06156', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作人員原先設定的目標為：「減少家庭成員彼此批評的次數」，後來社會工作人員將此目標修正 為「增加家庭成員對彼此力量與優勢的覺察，並增加正向訊息的次數」。請問此種修正的策略，屬於下 列那項目標設定的技巧？', '["目標設定應用正向語言敘述並強調成長", "目標設定必須清楚說明、不能簡短帶過", "目標設定必須避免有爭議的目標", "目標設定必須符合案主的現有能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06157', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「後續追蹤」是社會工作人員在結案後，必須執行的工作。下列有關後續追蹤的敘述，何者錯誤？', '["「後續追蹤」有助於社會工作人員評鑑（evaluation）服務的成效", "「後續追蹤」可以減緩結案時的負向影響", "「後續追蹤」可以檢視案主改變的持久性", "「後續追蹤」有助於案主維持與社會工作人員持續的依附關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06158', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'essay', '社會團體工作的結束階段對團體成員而言是一個關鍵過程。你是一位團體領導者，
